var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"자, 약속한 대로 약을 가져왔다.","JPN":"さあ、約束どおり薬を持ってきた。","ENG":"Hey, I brought the drug as promised.","TWN":"拿去，這是說好的藥。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"양은 부하들이 쓸 만큼 충분해. 블랙 네트워크에서 구하는 것보단 품질이 좋을 거야.","JPN":"部下が全員使うのに十分な量だ。ブラックネットワークで手に入れるよりはいい品だろう。","ENG":"There’s enough for the men. It’s better stuff than what you’d find on the Dark Network.","TWN":"這些量夠你的手下們用，而且品質比黑色網路上賣的還好。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤헤……. 대금은 안 받아도 되는 거야?","JPN":"へへ……金はとらないのか？","ENG":"Heh... You don’t need me to pay you?","TWN":"嘿嘿……真的不用付錢嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"필요없어. 우리는 지금 거래가 아니라 협조를 하고 있으니까.","JPN":"必要ない。私たちは今、取引ではなく協力しているだけだから。","ENG":"No. We're not trading now, but cooperating.","TWN":"不用，因為我們現在不是交易關係，而是合作關係。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"용병 신분으로 여기 와 있다는 사실을 잊진 않았겠지?","JPN":"傭兵の身でここに来てるってこと、忘れてはいないだろうな？","ENG":"You didn’t forget that you came here as a mercenary, did you?","TWN":"你沒忘記，你是以傭兵的身分來到這裡的吧？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"결행 전까지, 괜한 트러블은 일으키지 마.","JPN":"決行まで変なトラブルを起こすな。","ENG":"Don’t cause any unnecessary trouble until it’s all over.","TWN":"在行動前不要惹事生非。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"물론이지, 나리. 쥐 죽은 듯이 조용히 지낼 거야.","JPN":"もちろんさ、旦那。じっと過ごすよ。","ENG":"Sure thing, miss. I’ll be as quiet as a mouse.","TWN":"那是當然的，姊。我會像死老鼠般安靜。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"아, 그렇지. 참. 고마워, 나리.","JPN":"ああ、そうだ。ありがとな、旦那。","ENG":"Ah, right. Well. Thank you, miss.","TWN":"對了，姊，真的很謝謝你。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"고맙다니?","JPN":"ありがとうって？","ENG":"What do you mean thank you?","TWN":"謝謝我？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"나리가 아니었으면, 나 같은 건 이런 짓 엄두도 못 냈을 거야.","JPN":"旦那がいなけりゃ、俺なんかにこんなこと、とてもできなかった。","ENG":"If it wasn’t for you, I wouldn’t have been able to do this.","TWN":"要不是姊，像我這種貨色，根本想都不敢想會有這一天。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"나는 원래 부하들을 잔뜩 거느릴 만큼 대단한 사람도 아니고…….","JPN":"俺は元々こんな多くの手下を率るくらいすごい奴でもないし……","ENG":"I’m not really a good enough leader to have this many men under me...","TWN":"我本來就不太會帶領人……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"아버지가 돌아가신 날 나리가 나타나지 않았다면 분명 아무것도 못하다 정부군 놈들에게 죽었을 거야.","JPN":"おやじが亡くなった日、旦那が現れなかったらきっと何もできずに政府軍の野郎どもにやられてた。","ENG":"If you didn’t show up the day my father died, the government soldiers would have killed me.","TWN":"我爸死掉的那一天，若不是姊的出現，我應該毫無招架之力，只能死在政府軍的手裡。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……저 자, 정신이 불안정해 보이는군.","JPN":"……あの者、精神が不安定であるな。","ENG":"....That guy. Looks like he is a little unstable.","TWN":"……那個人，精神狀況看起來不太穩定。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"소녀여. 그대가 저 자에게 건넨 약은 인간의 이성을 흐리는 작용을 하고 있다.","JPN":"少女よ。そなたがあの者に渡した薬は人間の理性を濁らせる作用をしている。","ENG":"Girl, the drug that you provided clouds a human’s ability to reason.","TWN":"少女，你給他的藥會使人的精神產生混亂。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"저들이 원하던 거야. 나는 그걸 들어 줬을 뿐이고.","JPN":"彼らが望んだんだ。私はそれを叶えてやっただけ。","ENG":"It’s what they wanted. I just gave them what they want.","TWN":"這就是他們所希望的，而我只是照他們所希望的去做。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"알고 있어? 저들에게 이 도시는 적진 한복판이야.","JPN":"知ってるか？　彼らにとってこの街は敵陣のど真ん中だ。","ENG":"Don’t you know? To them, this city is right in the middle of enemy territory.","TWN":"你知道嗎？對他們而言，這座城市就等於是敵營的中心。"},"stage":{"bg":"HARMONY_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};